create extension if not exists pgcrypto;
create table if not exists public.market_os_ambassadors (id uuid primary key default gen_random_uuid(), name text not null, phone text, email text, city text, territory text, status text default 'candidate', tier text default 'starter', score numeric default 0, payload jsonb not null default '{}'::jsonb, created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists public.market_os_ambassador_missions (id uuid primary key default gen_random_uuid(), ambassador_id uuid references public.market_os_ambassadors(id) on delete cascade, title text not null, status text default 'assigned', priority text default 'normal', due_at timestamptz, proof_required boolean default true, payload jsonb not null default '{}'::jsonb, created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists public.market_os_ambassador_leads (id uuid primary key default gen_random_uuid(), ambassador_id uuid references public.market_os_ambassadors(id) on delete set null, lead_name text, phone text, segment text, status text default 'new', value_mad numeric default 0, payload jsonb not null default '{}'::jsonb, created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists public.market_os_ambassador_proofs (id uuid primary key default gen_random_uuid(), ambassador_id uuid references public.market_os_ambassadors(id) on delete cascade, mission_id uuid references public.market_os_ambassador_missions(id) on delete cascade, title text not null, proof_url text, status text default 'submitted', payload jsonb not null default '{}'::jsonb, created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists public.market_os_ambassador_payouts (id uuid primary key default gen_random_uuid(), ambassador_id uuid references public.market_os_ambassadors(id) on delete cascade, amount_mad numeric default 0, status text default 'draft', period text, payload jsonb not null default '{}'::jsonb, created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists public.market_os_ambassador_training (id uuid primary key default gen_random_uuid(), ambassador_id uuid references public.market_os_ambassadors(id) on delete cascade, module_title text not null, status text default 'not_started', score numeric default 0, completed_at timestamptz, payload jsonb not null default '{}'::jsonb, created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists public.market_os_ambassador_compliance (id uuid primary key default gen_random_uuid(), ambassador_id uuid references public.market_os_ambassadors(id) on delete cascade, check_title text not null, status text default 'pending', severity text default 'medium', payload jsonb not null default '{}'::jsonb, created_at timestamptz default now(), updated_at timestamptz default now());
alter table public.market_os_ambassadors enable row level security; alter table public.market_os_ambassador_missions enable row level security; alter table public.market_os_ambassador_leads enable row level security; alter table public.market_os_ambassador_proofs enable row level security; alter table public.market_os_ambassador_payouts enable row level security; alter table public.market_os_ambassador_training enable row level security; alter table public.market_os_ambassador_compliance enable row level security;
do $$ declare t text; begin foreach t in array array['market_os_ambassadors','market_os_ambassador_missions','market_os_ambassador_leads','market_os_ambassador_proofs','market_os_ambassador_payouts','market_os_ambassador_training','market_os_ambassador_compliance'] loop execute format('create policy %I on public.%I for all to authenticated using (true) with check (true)', t||'_authenticated_all', t); end loop; exception when duplicate_object then null; end $$;
